#include "rsbench.cuh"

__global__ void xs_lookup_kernel_baseline(Input in, SimulationData GSD)
{
    unsigned int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= in.lookups) return;

    uint64_t seed = STARTING_SEED;

    seed = fast_forward_LCG(seed, 2 * i);

    double E = LCG_random_double(&seed);
    int mat = pick_mat(&seed);

    double macro_xs[4] = {0};

    calculate_macro_xs(macro_xs, mat, E, in,
                       GSD.num_nucs, GSD.mats, GSD.max_num_nucs, GSD.concs,
                       GSD.n_windows, GSD.pseudo_K0RS, GSD.windows, GSD.poles,
                       GSD.max_num_windows, GSD.max_num_poles);

    double max = -DBL_MAX;
    int max_idx = 0;
    for (int x = 0; x < 4; x++)
    {
        if (macro_xs[x] > max)
        {
            max = macro_xs[x];
            max_idx = x;
        }
    }

    atomicAdd(GSD.verification, (unsigned long)(max_idx + 1));
}

void run_event_based_simulation(Input input, SimulationData data, unsigned long *vhash_result)
{
    printf("Beginning baseline event based simulation...\n");

    // Allocate verification on device
    unsigned long *d_verification;
    gpuErrchk(cudaMalloc((void **)&d_verification, sizeof(unsigned long)));
    gpuErrchk(cudaMemset(d_verification, 0, sizeof(unsigned long)));

    int threadsPerBlock = 256;
    int blocksPerGrid = (input.lookups + threadsPerBlock - 1) / threadsPerBlock;

    xs_lookup_kernel_baseline<<<blocksPerGrid, threadsPerBlock>>>(input, data);
    gpuErrchk(cudaPeekAtLastError());
    gpuErrchk(cudaDeviceSynchronize());

    unsigned long h_verification = 0;
    gpuErrchk(cudaMemcpy(&h_verification, d_verification, sizeof(unsigned long), cudaMemcpyDeviceToHost));

    gpuErrchk(cudaFree(d_verification));

    *vhash_result = h_verification;
}

